// Extract posts array from AI output
const output = $input.first().json.output;
let posts = [];

if (typeof output === 'string') {
  try {
    // Extract JSON from markdown code block (```json...```)
    const jsonMatch = output.match(/```json\n([\s\S]*?)\n```/);
    if (jsonMatch && jsonMatch[1]) {
      const parsed = JSON.parse(jsonMatch[1]);
      posts = parsed.posts || [];
    } else {
      // Fallback: try direct parsing
      const parsed = JSON.parse(output);
      posts = parsed.posts || [];
    }
  } catch (e) {
    console.log('Parse error:', e);
    return [];
  }
} else if (output && output.posts) {
  posts = output.posts;
}

// Return each post as a separate item
return posts.map(post => ({ json: post }));
